mapper.select:
SELECT A.POP_CD , A.POP_CNTS , A.POP_NM , A.POP_WIDTH , A.POP_HGT , DATE_FORMAT(A.OPEN_START_DT, '%Y-%m-%d') AS OPEN_START_DT , DATE_FORMAT(A.OPEN_END_DT, '%Y-%m-%d') AS OPEN_END_DT , A.POP_X_LOC , A.POP_Y_LOC , A.USE_YN , A.MENU_SYS_DIV FROM TB_POP A WHERE A.DEL_YN = 'N'
AND A.MENU_SYS_DIV = #{searchMenuSysDiv}
AND A.USE_YN = #{searchUseYn}
AND (A.POP_NM LIKE '%'||TRIM( #{searchPopNmCnts} )||'%' OR A.POP_CNTS LIKE '%'||TRIM( #{searchPopNmCnts} )||'%')
